sequence.script:
var initPayload   = JSON.parse(mc.getProperty("initialpayload"));
var paymentDet    = JSON.parse(mc.getProperty("paymentDetails"));
var paymentId     = mc.getProperty("paymentId") || "";
var paymentStatus = mc.getProperty("paymentStatus") || "";

var now = new Date().toISOString().replace(/\.\d{3}Z$/, 'Z');

var body = {
  "claimSettlementId": initPayload.claimSettlementId || "",
  "policyHolderId":    (initPayload.claims && initPayload.claims.policyHolderId) ? initPayload.claims.policyHolderId : "",
  "policyId":          (initPayload.claims && initPayload.claims.policyId)       ? initPayload.claims.policyId       : "",
  "claimId":           (initPayload.claims && initPayload.claims.claimId)        ? initPayload.claims.claimId        : "",
  "transactionDetails": {
    "id":                 paymentId,
    "status":             paymentStatus,
    "amount":             (paymentDet.transactionDetails && paymentDet.transactionDetails.amount)             ? paymentDet.transactionDetails.amount             : "",
    "currency":           (paymentDet.transactionDetails && paymentDet.transactionDetails.currency)           ? paymentDet.transactionDetails.currency           : "",
    "method":             (paymentDet.transactionDetails && paymentDet.transactionDetails.method)             ? paymentDet.transactionDetails.method             : "",
    "DateTime":           now,
    "payoutDestinationId":(paymentDet.transactionDetails && paymentDet.transactionDetails.payoutDestinationId)? paymentDet.transactionDetails.payoutDestinationId : ""
  }
};

mc.setPayloadJSON(body);
mc.setProperty("transactionDetails", JSON.stringify(body));
